"""
Edge-case tests for the QR Code Polynomial implementation.
"""

import sys
from pathlib import Path

_tests_dir = Path(__file__).parent.parent / "public"
if str(_tests_dir) not in sys.path:
    sys.path.insert(0, str(_tests_dir))

from fixtures import make_test_result

lib_path = Path(__file__).parent.parent.parent / "lib"
if str(lib_path) not in sys.path:
    sys.path.insert(0, str(lib_path))

import comp140_module5_z256 as z256

TEST_POINTS = {
    "test_add_term_new_power": 1,
    "test_add_term_zero_coefficient": 1,
    "test_subtract_term_new_power": 1,
    "test_subtract_term_self_cancel": 1,
    "test_multiply_by_term_zero": 1,
    "test_multiply_by_term_one": 1,
    "test_multiply_by_term_power_shift": 1,
    "test_add_term_immutable": 1,
    "test_subtract_term_immutable": 1,
    "test_multiply_by_term_immutable": 1,
    "test_add_polynomial_zero": 1,
    "test_subtract_polynomial_self": 1,
    "test_multiply_polynomial_identity": 1,
    "test_multiply_polynomial_commutative": 1,
    "test_remainder_less_degree": 1,
    "test_reed_solomon_handcalc_example": 1,
    "test_create_message_polynomial_example": 1,
    "test_create_generator_polynomial_k2_verify": 1,
    "test_create_generator_polynomial_k1": 1,
    "test_create_message_polynomial_single": 1,
    "test_reed_solomon_section2_example": 1,
    "test_add_polynomial_commutative": 1,
    "test_remainder_exact_division": 1,
}


def test_add_term_new_power(module):
    """Adding a term with a new power."""
    p = module.Polynomial({2: 5})
    result = p.add_term(3, 4)
    c4 = result.get_coefficient(4)
    c2 = result.get_coefficient(2)
    if c4 == 3 and c2 == 5:
        return make_test_result(True, "3x^4 + 5x^2", "correct")
    return make_test_result(False, "3x^4 + 5x^2", f"{c4}x^4 + {c2}x^2")


def test_add_term_zero_coefficient(module):
    """Adding zero-coefficient term doesn't change polynomial."""
    p = module.Polynomial({2: 5})
    result = p.add_term(0, 2)
    c2 = result.get_coefficient(2)
    if c2 == 5:
        return make_test_result(True, "5x^2", "correct")
    return make_test_result(False, "5x^2", f"{c2}x^2")


def test_subtract_term_new_power(module):
    """Subtracting a term from a power not present."""
    p = module.Polynomial()
    result = p.subtract_term(5, 3)
    c3 = result.get_coefficient(3)
    expected = z256.sub(0, 5)
    if c3 == expected:
        return make_test_result(True, f"{expected}x^3", "correct")
    return make_test_result(False, f"{expected}x^3", f"{c3}x^3")


def test_subtract_term_self_cancel(module):
    """Subtracting a term equal to existing gives 0 coefficient."""
    p = module.Polynomial({3: 42})
    result = p.subtract_term(42, 3)
    c3 = result.get_coefficient(3)
    if c3 == 0:
        return make_test_result(True, "0", "correct")
    return make_test_result(False, "0", f"{c3}x^3")


def test_multiply_by_term_zero(module):
    """Multiplying by zero coefficient gives zero polynomial."""
    p = module.Polynomial({3: 10, 1: 20})
    result = p.multiply_by_term(0, 5)
    deg = result.get_degree()
    if deg == 0 and result.get_coefficient(0) == 0:
        return make_test_result(True, "zero poly", "correct")
    return make_test_result(False, "zero poly", f"degree={deg}")


def test_multiply_by_term_one(module):
    """Multiplying by 1*x^0 gives the same polynomial."""
    p = module.Polynomial({3: 10, 1: 20})
    result = p.multiply_by_term(1, 0)
    if result == p:
        return make_test_result(True, "same polynomial", "correct")
    return make_test_result(False, "same polynomial", str(result))


def test_multiply_by_term_power_shift(module):
    """Multiplying by x^2 shifts powers up by 2."""
    p = module.Polynomial({3: 10, 1: 20, 0: 5})
    result = p.multiply_by_term(1, 2)
    c5 = result.get_coefficient(5)
    c3 = result.get_coefficient(3)
    c2 = result.get_coefficient(2)
    if c5 == 10 and c3 == 20 and c2 == 5:
        return make_test_result(True, "10x^5 + 20x^3 + 5x^2", "correct")
    return make_test_result(False, "10x^5 + 20x^3 + 5x^2",
                            f"{c5}x^5 + {c3}x^3 + {c2}x^2")


def test_add_term_immutable(module):
    """add_term should not mutate the original polynomial."""
    p = module.Polynomial({2: 5})
    _ = p.add_term(3, 4)
    c4 = p.get_coefficient(4)
    c2 = p.get_coefficient(2)
    if c4 == 0 and c2 == 5:
        return make_test_result(True, "original unchanged", "correct")
    return make_test_result(False, "original unchanged", f"c4={c4}, c2={c2}")


def test_subtract_term_immutable(module):
    """subtract_term should not mutate the original polynomial."""
    p = module.Polynomial({2: 5})
    _ = p.subtract_term(3, 2)
    c2 = p.get_coefficient(2)
    if c2 == 5:
        return make_test_result(True, "original unchanged", "correct")
    return make_test_result(False, "original unchanged", f"c2={c2}")


def test_multiply_by_term_immutable(module):
    """multiply_by_term should not mutate the original polynomial."""
    p = module.Polynomial({2: 5})
    _ = p.multiply_by_term(3, 1)
    c2 = p.get_coefficient(2)
    c3 = p.get_coefficient(3)
    if c2 == 5 and c3 == 0:
        return make_test_result(True, "original unchanged", "correct")
    return make_test_result(False, "original unchanged", f"c2={c2}, c3={c3}")


def test_add_polynomial_zero(module):
    """Adding zero polynomial gives the same polynomial."""
    p = module.Polynomial({3: 10, 1: 20})
    zero = module.Polynomial()
    result = p.add_polynomial(zero)
    if result == p:
        return make_test_result(True, "same polynomial", "correct")
    return make_test_result(False, "same polynomial", str(result))


def test_subtract_polynomial_self(module):
    """Subtracting a polynomial from itself gives zero."""
    p = module.Polynomial({3: 10, 1: 20, 0: 5})
    result = p.subtract_polynomial(p)
    deg = result.get_degree()
    if deg == 0:
        return make_test_result(True, "zero polynomial", "correct")
    return make_test_result(False, "zero polynomial", f"degree={deg}")


def test_multiply_polynomial_identity(module):
    """Multiplying by constant 1 polynomial gives itself."""
    p = module.Polynomial({3: 10, 1: 20})
    one = module.Polynomial({0: 1})
    result = p.multiply_by_polynomial(one)
    if result == p:
        return make_test_result(True, "same polynomial", "correct")
    return make_test_result(False, "same polynomial", str(result))


def test_multiply_polynomial_commutative(module):
    """Polynomial multiplication should be commutative."""
    p = module.Polynomial({2: 3, 0: 1})
    q = module.Polynomial({1: 5, 0: 2})
    pq = p.multiply_by_polynomial(q)
    qp = q.multiply_by_polynomial(p)
    if pq == qp:
        return make_test_result(True, "p*q == q*p", "correct")
    return make_test_result(False, "p*q == q*p", f"p*q={pq}, q*p={qp}")


def test_add_polynomial_commutative(module):
    """Polynomial addition should be commutative."""
    p = module.Polynomial({3: 10, 1: 20})
    q = module.Polynomial({2: 5, 1: 15, 0: 7})
    pq = p.add_polynomial(q)
    qp = q.add_polynomial(p)
    if pq == qp:
        return make_test_result(True, "p+q == q+p", "correct")
    return make_test_result(False, "p+q == q+p", f"p+q={pq}, q+p={qp}")


def test_remainder_less_degree(module):
    """If numerator degree < denominator degree, remainder is the numerator."""
    p = module.Polynomial({1: 5, 0: 3})
    q = module.Polynomial({3: 1, 0: 1})
    result = p.remainder(q)
    if result == p:
        return make_test_result(True, "5x + 3", "correct")
    return make_test_result(False, "5x + 3", str(result))


def test_remainder_exact_division(module):
    """If polynomial divides evenly, remainder should be zero."""
    # (x^2 + 3x + 2) = (x + 1)(x + 2), so dividing by (x+1) in Z256
    # Actually let's use a simpler case: 6x^2 divided by 3x gives remainder 0
    p = module.Polynomial({2: 6})
    q = module.Polynomial({1: 3})
    result = p.remainder(q)
    deg = result.get_degree()
    if deg == 0 and result.get_coefficient(0) == 0:
        return make_test_result(True, "zero remainder", "correct")
    return make_test_result(False, "zero remainder", str(result))


def test_reed_solomon_handcalc_example(module):
    """Verify the hand-calculated example: M=[104,105,33,33], k=2.
    Expected remainder = 69x + 68.
    """
    result = module.reed_solomon_correction([104, 105, 33, 33], 2)
    c1 = result.get_coefficient(1)
    c0 = result.get_coefficient(0)
    deg = result.get_degree()
    if c1 == 69 and c0 == 68 and deg == 1:
        return make_test_result(True, "69x + 68", "correct")
    return make_test_result(False, "69x + 68", f"{c1}x + {c0} (deg={deg})")


def test_create_message_polynomial_example(module):
    """Verify message polynomial: M=[104,105,33,33], k=2.
    Expected: 104x^5 + 105x^4 + 33x^3 + 33x^2.
    """
    poly = module.create_message_polynomial([104, 105, 33, 33], 2)
    c5 = poly.get_coefficient(5)
    c4 = poly.get_coefficient(4)
    c3 = poly.get_coefficient(3)
    c2 = poly.get_coefficient(2)
    if c5 == 104 and c4 == 105 and c3 == 33 and c2 == 33:
        return make_test_result(True, "104x^5 + 105x^4 + 33x^3 + 33x^2", "correct")
    return make_test_result(False, "104x^5 + 105x^4 + 33x^3 + 33x^2",
                            f"{c5}x^5 + {c4}x^4 + {c3}x^3 + {c2}x^2")


def test_create_generator_polynomial_k2_verify(module):
    """Generator for k=2: (x-1)(x-2) = x^2 + 3x + 2 in Z256."""
    poly = module.create_generator_polynomial(2)
    c2 = poly.get_coefficient(2)
    c1 = poly.get_coefficient(1)
    c0 = poly.get_coefficient(0)
    if c2 == 1 and c1 == 3 and c0 == 2:
        return make_test_result(True, "x^2 + 3x + 2", "correct")
    return make_test_result(False, "x^2 + 3x + 2",
                            f"{c2}x^2 + {c1}x + {c0}")


def test_create_generator_polynomial_k1(module):
    """Generator for k=1: (x - 2^0) = x + 255 in Z256."""
    poly = module.create_generator_polynomial(1)
    c1 = poly.get_coefficient(1)
    c0 = poly.get_coefficient(0)
    expected_c0 = z256.sub(0, 1)
    if c1 == 1 and c0 == expected_c0:
        return make_test_result(True, f"x + {expected_c0}", "correct")
    return make_test_result(False, f"x + {expected_c0}", f"{c1}x + {c0}")


def test_create_message_polynomial_single(module):
    """Single byte message: [42] with k=3 => 42*x^3."""
    poly = module.create_message_polynomial([42], 3)
    c3 = poly.get_coefficient(3)
    deg = poly.get_degree()
    if c3 == 42 and deg == 3:
        return make_test_result(True, "42x^3", "correct")
    return make_test_result(False, "42x^3", f"{c3}x^{deg}")


def test_reed_solomon_section2_example(module):
    """Section 2 example: M=[32,91,11,120,209,114,220,77], k=2.
    Remainder should have degree < 2.
    """
    result = module.reed_solomon_correction(
        [32, 91, 11, 120, 209, 114, 220, 77], 2)
    deg = result.get_degree()
    if deg < 2:
        return make_test_result(True, "degree < 2", "correct")
    return make_test_result(False, "degree < 2", f"degree={deg}")
